function cleanEtu(value) {
    if (!value) return null;

    const match = String(value).match(/(\d+)/);

    return match
        ? parseInt(match[1], 10)
        : null;
}

function cleanPromotion(value) {
    if (!value) return null;

    const match = String(value).match(/(\d+)/);

    if (!match) {
        return null;
    }

    const promoNum = parseInt(match[1], 10);

    return promoNum < 17
        ? `DS P${promoNum}`
        : `INF P${promoNum}`;
}

function cleanRegistrationDate(value) {
    if (!value) {
        return null;
    }

    const match = String(value).match(
        /^(\d{2})\/(\d{2})\/(\d{4})/
    );

    if (!match) {
        return null;
    }

    const [, day, month, year] = match;

    return `${year}-${month}-${day}`;
}

const registrations = items.map(item => {

    const data = item.json.body ?? item.json;

    return {
        registrationDate: cleanRegistrationDate(
            data["Horodateur"]
        ),

        fullName:
            data["Nom et prénom"]?.trim() ?? null,

        etu: cleanEtu(
            data["ETU (ex: 3173)"]
        ),

        promotion: cleanPromotion(
            data["Promotion (ex: DS P5, INF P9-A)"]
        ),

        email:
            data["Email"]?.trim().toLowerCase() ?? null,

        registrationActivityName:
            data["Parmi les domaines suivants, lequel vous intéresse le plus? "] ??
            data["Parmi les domaines suivants, lequel vous intéresse le plus?"] ??
            null,

        registrationActivityLevelString:
            data["Précisez votre niveau"] ?? null,

        facebookProfileLink:
            data["Lien vers votre compte facebook"] ?? null,

        registrationInterest:
            data["Pourquoi avez vous choisi d'intégrer le club d'art? :D"] ?? null
    };
});

// Suppression des doublons par ETU
const seenEtu = new Set();

const uniqueRegistrations = registrations.filter(registration => {

    // On garde les lignes sans ETU
    if (registration.etu === null) {
        return true;
    }

    if (seenEtu.has(registration.etu)) {
        return false;
    }

    seenEtu.add(registration.etu);
    return true;
});

return [
    {
        json: {
            registrations: uniqueRegistrations
        }
    }
];

const now = new Date().toISOString();

const isError = items.some(item => item.json?.error);

if (isError) {
  const result = items.map(item => {
    return {
      json: {
        type: "error",
        message: "Erreur lors de l'orchestration des inscriptions",
        details: JSON.stringify(item.json.error ?? item.json),
        date: now
      }
    };
  });

  return result;
}

return items.map(item => {
  return {
    json: {
      type: "success",
      message: "Inscription(s) orchestrée(s) avec succès!",
      details: JSON.stringify(item.json),
      date: now
    }
  };
});
